sql:
SELECT AVG(amount) AS average_loan_amount
FROM loan_applicants
WHERE month_num > (SELECT MAX(month_num) FROM loan_applicants) - 12;

SELECT age, gender, COUNT(*) AS applicant_count
FROM loan_applicants
GROUP BY age, gender;

SELECT applicant_id
FROM loan_applicants
WHERE amount > (SELECT AVG(amount) FROM loan_applicants);

SELECT applicant_id, status
FROM loan_status
WHERE status = 'Approved';

SELECT AVG(amount) AS average_loan_amount
FROM loan_applicants
WHERE age > 30;

SELECT AVG(amount_paid) AS average_payment_amount
FROM repayment_history
WHERE payment_date BETWEEN '2023-05-01' AND '2023-05-31';

SELECT applicant_id, risk_score
FROM risk_assessment
WHERE risk_score > 5;
